CREATE TABLE predictions (
      id TEXT PRIMARY KEY,
      generated_at INTEGER NOT NULL,
      context_hash TEXT NOT NULL,
      predictions TEXT NOT NULL,
      outcome TEXT,
      created_at INTEGER DEFAULT (strftime('%s', 'now'))
    );
