CREATE INDEX idx_events_session ON events(session_id);
CREATE INDEX idx_events_type ON events(type);
CREATE INDEX idx_events_timestamp ON events(timestamp DESC);
CREATE INDEX idx_events_processed ON events(processed);
CREATE INDEX idx_beliefs_domain ON beliefs(domain);
CREATE INDEX idx_beliefs_active ON beliefs(invalidated_at) WHERE invalidated_at IS NULL;
CREATE INDEX idx_beliefs_confidence ON beliefs(confidence DESC);
CREATE TRIGGER events_ai AFTER INSERT ON events BEGIN
      INSERT INTO events_fts(rowid, searchable_text) VALUES (NEW.rowid, NEW.searchable_text);
    END;
CREATE TRIGGER events_ad AFTER DELETE ON events BEGIN
      INSERT INTO events_fts(events_fts, rowid, searchable_text) VALUES('delete', OLD.rowid, OLD.searchable_text);
    END;
CREATE TRIGGER events_au AFTER UPDATE ON events BEGIN
      INSERT INTO events_fts(events_fts, rowid, searchable_text) VALUES('delete', OLD.rowid, OLD.searchable_text);
      INSERT INTO events_fts(rowid, searchable_text) VALUES (NEW.rowid, NEW.searchable_text);
    END;
CREATE TRIGGER beliefs_ai AFTER INSERT ON beliefs BEGIN
      INSERT INTO beliefs_fts(rowid, text, tags) VALUES (NEW.rowid, NEW.text, NEW.tags);
    END;
CREATE TRIGGER beliefs_ad AFTER DELETE ON beliefs BEGIN
      INSERT INTO beliefs_fts(beliefs_fts, rowid, text, tags) VALUES('delete', OLD.rowid, OLD.text, OLD.tags);
    END;
CREATE TRIGGER beliefs_au AFTER UPDATE ON beliefs BEGIN
      INSERT INTO beliefs_fts(beliefs_fts, rowid, text, tags) VALUES('delete', OLD.rowid, OLD.text, OLD.tags);
      INSERT INTO beliefs_fts(rowid, text, tags) VALUES (NEW.rowid, NEW.text, NEW.tags);
    END;
PRAGMA writable_schema=OFF;
COMMIT;
